import xml.etree.ElementTree as ET

def parse_xml(file):
    tree = ET.parse(file)
    root = tree.getroot()
    
    result_dict = {}
    
    for child in root:
        name = child.tag
        value = child.text
        
        if child.attrib:  # handle attributes on the XML tag (if any)
            attr_str = ' '.join(f'{k}={v}' for k, v in child.attrib.items())
            name += f" {attr_str}"
    
        result_dict[name] = value
        
    return result_dict